INSERT [dbo].[EmailTemplate] ([Name], [Description], [Definition], [Format], [AuditDate], [AuditUser], [Version]) VALUES ( N'PickingNotification', N'This template shows the details of what was picked on an order', N'{{     headerImage(     {       imageUrl:''https://www.granitewms.com/wp-content/uploads/2020/07/GraniteWMS-1.png'',       backgroundColor:''#182026''     }) }}  # Order {{documentNumber}} picked!  Dear {{customerName}},  Your order has been picked and is pending collection by the courier.   Keep an eye out for further updates!  {{         ''SELECT Code, MasterItem.[Description], CAST(SUM([Transaction].ActionQty) as int) as Qty         FROM [Transaction] INNER JOIN         Document ON [Transaction].Document_id = Document.ID INNER JOIN         DocumentDetail ON [Transaction].DocumentLine_id = DocumentDetail.ID INNER JOIN         MasterItem ON DocumentDetail.Item_id = MasterItem.ID         WHERE Document.Number = @documentNumber         GROUP BY Code, MasterItem.[Description]''     | dbSelect({documentNumber})     | table({backgroundColor: ''#182026'', textColor: ''white''}) }}  {{     footerItem(     {          imageUrl:''https://cdn1.iconfinder.com/data/icons/logotypes/32/square-facebook-1024.png'',         imageWidth: 50,         url:''https://www.facebook.com/StarWarsAfrica/''     })     | footerItem(     {          imageUrl:''https://cdn2.iconfinder.com/data/icons/social-icons-33/128/Instagram-1024.png'',         imageWidth: 50,         url:''https://www.instagram.com/starwars''     })     | footerBlock({backgroundColor:''#182026'', textColor:''lightgray'' })  }} ', N'MARKDOWN', GETDATE(), N'AUTOMATION', 1)